`,cs=[{id:1,titulo:"Clarity Changes Everything",contenido:[{tipo:"subtitulo",text:"Most people don\u2019t lack options."},{tipo:"giro",text:"They lack clarity."},{tipo:"parrafo",text:"When direction is unclear, everything feels harder."},{tipo:"parrafo",text:"Decisions take longer."},{tipo:"parrafo",text:"Effort increases."},{tipo:"parrafo",text:"Confidence drops."},{tipo:"parrafo",text:"Not because the path is complex \u2014 "},{tipo:"parrafoBloque",text:"but because it\u2019s undefined."},{tipo:"giro",text:"Clarity simplifies."},{tipo:"parrafo",text:"It allows you to focus your energy,"},{tipo:"parrafo",text:"communicate your value,"},{tipo:"parrafoBloque",text:"and move forward with intention."},{tipo:"cierreBold",text:"Clarity is not a luxury."},{tipo:"cierreRegular",text:"It is the foundation."}]},{id:2,titulo:"Positioning Shapes Perception",contenido:[{tipo:"subtitulo",text:"Most people don\u2019t struggle because they lack \nexperience."},{tipo:"giro",text:"They struggle because they don\u2019t position it \nclearly."},{tipo:"parrafo",text:"Experience alone doesn\u2019t communicate value."},{tipo:"parrafoBloque",text:"It needs structure, context, and direction."},{tipo:"parrafo",text:"Without positioning, work feels fragmented."},{tipo:"parrafo",text:"Strengths are diluted."},{tipo:"parrafoBloque",text:"The message is unclear."},{tipo:"parrafo",text:"People don\u2019t see everything you\u2019ve done."},{tipo:"parrafo",text:"They can only understand what you make clear."},{tipo:"giro",text:"Positioning brings coherence."},{tipo:"parrafo",text:"It connects your experience into a clear narrative"},{tipo:"parrafoBloque",text:"others can understand, and trust."},{tipo:"cierreBold",text:"Positioning is not about reinvention."},{tipo:"cierreRegular",text:"It\u2019s about alignment."}]},{id:3,titulo:"Decisions Create Direction",contenido:[{tipo:"subtitulo",text:"Most people don\u2019t lack experience."},{tipo:"giro",text:"They lack the ability to make decisions."},{tipo:"parrafo",text:"Without decisions, movement can feel like"},{tipo:"parrafo",text:"progress,"},{tipo:"parrafoBloque",text:"but leads nowhere."},{tipo:"parrafo",text:"Options remain open."},{tipo:"parrafo",text:"Energy is scattered"},{tipo:"parrafoBloque",text:"Momentum fades."},{tipo:"parrafo",text:"Clarity informs decisions."},{tipo:"parrafoBloque",text:"And decisions create direction."},{tipo:"parrafo",text:"Each decision defines what matters,"},{tipo:"parrafo",text:"and eliminates what doesn\u2019t."},{tipo:"cierreBold",text:"Progress doesn\u2019t come from doing more."},{tipo:"cierreRegular",text:"It comes from deciding what matters."}]},{id:4,titulo:"Relationships Determine Results.",contenido:[{tipo:"parrafo",text:"Decisions are influenced by trust."},{tipo:"parrafoBloque",text:"Direction is shaped through conversation."},{tipo:"parrafo",text:"Without strong relationships, possibilities narrow."},{tipo:"parrafo",text:"Conversations lose depth."},{tipo:"parrafoBloque",text:"Momentum slows."},{tipo:"parrafo",text:"What appears as a lack of opportunity"},{tipo:"parrafo",text:"is often a lack of connection \u2013"},{tipo:"parrafoBloque",text:"or relationships  that have not been sustained."},{tipo:"giro",text:"Relationships create context."},{tipo:"parrafo",text:"They are built over time \u2014 "},{tipo:"parrafo",text:"through consistency, trust, and presence \u2014"},{tipo:"parrafo",text:"and shaped by how we show up \u2014"},{tipo:"parrafoBloque",text:"respect, transparency, alignment."},{tipo:"parrafo",text:"They open doors."},{tipo:"parrafo",text:"They accelerate decisions."},{tipo:"parrafo",text:"They shape how we are seen and understood."},{tipo:"cierreBold",text:"Results are relational."}]},{id:5,titulo:"SAETA",contenido:[{tipo:"subtitulo",text:"A diagnostic lens for clarity and direction."},{tipo:"parrafo",text:"It helps determine"},{tipo:"parrafo",text:"where someone is,"},{tipo:"parrafo",text:"what the moment requires,"},{tipo:"parrafoBloque",text:"and how to move forward."},{tipo:"parrafo",text:"It brings structure without rigidity."},{tipo:"cierreBold",text:"Clarity comes before action."}]},{id:6,titulo:"Networking is not Transactional",contenido:[{tipo:"subtitulo",text:"Networking is often approached with urgency \u2014 \nor not at all."},{tipo:"parrafo",text:"A need."},{tipo:"parrafo",text:"A request"},{tipo:"parrafoBloque",text:" A goal."},{tipo:"parrafo",text:"It becomes about reaching out,"},{tipo:"parrafo",text:"asking for time,"},{tipo:"parrafo",text:"or asking for help."},{tipo:"giro",text:"This is where people get stuck."},{tipo:"parrafoBloque",text:"Strong relationships are built over time \u2013"},{tipo:"parrafo",text:"Through consistency."},{tipo:"parrafo",text:"Through presence"},{tipo:"parrafoBloque",text:"Through genuine engagement."},{tipo:"parrafo",text:"What appears as a lack of opportunity"},{tipo:"parrafoBloque",text:"often a lack of connection."},{tipo:"cierreBold",text:"Networking is not a transaction."},{tipo:"cierreRegular",text:"It is a relationship over time."}]},{id:7,titulo:"The Pitch",contenido:[{tipo:"subtitulo",text:"Most people think of the pitch as something to prepare."},{tipo:"parrafo",text:"A summary"},{tipo:"parrafo",text:"A script."},{tipo:"parrafo",text:"A way to introduce themselves."},{tipo:"giro",text:"The pitch is not something you memorize."},{tipo:"parrafo",text:"A strong pitch is not about saying more."},{tipo:"parrafo",text:"It is about knowing what you want to be known for,"},{tipo:"parrafo",text:"how your experience connects,"},{tipo:"parrafoBloque",text:"and what matters now."},{tipo:"parrafoBloque",text:"It evolves over time."},{tipo:"parrafo",text:"It changes depending on the context,"},{tipo:"parrafo",text:"the audience,"},{tipo:"parrafo",text:"the moment,"},{tipo:"parrafoBloque",text:"and the question."},{tipo:"parrafo",text:"When it is clear, it creates alignment."},{tipo:"parrafoBloque",text:"When it is not, it creates confusion."},{tipo:"parrafo",text:"The pitch is not a statement."},{tipo:"cierreBold",text:"It is a reflection of clarity \u2014 "},{tipo:"cierreRegular",text:"in the present moment."}]},{id:8,titulo:"Interviewing Is a Conversation",contenido:[{tipo:"subtitulo",text:"Most people approach interviewing as an \n evaluation "},{tipo:"parrafo",text:"A test."},{tipo:"parrafo",text:"A performance."},{tipo:"parrafo",text:"A moment to prove themselves."},{tipo:"giro",text:"And in part, it is."},{tipo:"giro",text:"But it happens within a conversation."},{tipo:"parrafo",text:"In some contexts, the process may include "},{tipo:"parrafoBloque",text:"assessments, tasks, or presentations."},{tipo:"parrafo",text:"These are part of the process."},{tipo:"parrafo",text:"They do not define the interaction."},{tipo:"cierreBold",text:"An interview is a conversation."},{tipo:"cierreRegular",text:"The process is a series of conversations."}]}],us=Oe.div``,ps=(Oe.div`
